import React from 'react';
import { Outlet, useLocation } from 'react-router-dom';
import PhotoSide from '../components/PhotoSide';
import './AuthLayout.css';
import { motion, AnimatePresence } from 'framer-motion';

function AuthLayout() {
  const location = useLocation();

  const slideVariants = {
    initial: (direction) => ({
      x: direction > 0 ? '100%' : '-100%',
      opacity: 0,
    }),
    animate: {
      x: '0%',
      opacity: 1,
      transition: { duration: 0.6, ease: 'easeInOut' },
    },
    exit: (direction) => ({
      x: direction < 0 ? '100%' : '-100%',
      opacity: 0,
      transition: { duration: 0.6, ease: 'easeInOut' },
    }),
  };

  const reverseRoutes = ['/forgot-password', '/reset-password'];
  const direction = reverseRoutes.includes(location.pathname) ? 1 : -1;

  return (
    <div className="auth-slider-container">
      <AnimatePresence mode="wait" custom={direction}>
        <motion.div
          key={location.pathname}
          className="auth-slide"
          variants={slideVariants}
          initial="initial"
          animate="animate"
          exit="exit"
          custom={direction}
        >
          <div className="auth-slide-content">
            <div className="photo-side">
              <PhotoSide />
            </div>
            <div className="form-side">
              <Outlet />
            </div>
          </div>
        </motion.div>
      </AnimatePresence>
    </div>
  );
}

export default AuthLayout;
